                        batch_data[field_name].append(int(datetime.now().timestamp() * 1000))
                    elif field_type == DataType.JSON:
                        batch_data[field_name].append({})
                    elif field_type == DataType.INT16 or field_type == DataType.INT64:
                        batch_data[field_name].append(0)
                    elif field_type == DataType.ARRAY:
                        batch_data[field_name].append([0, 0])
                    elif field_type == DataType.FLOAT_VECTOR:
                        batch_data[field_name].append([])
                    else:
                        batch_data[field_name].append("")
            # 批量插入
