                import traceback
                traceback.print_exc()
        collection.flush()
        print(f"[SUCCESS] Partition: {total_inserted}/{total_processed} records")
        yield {
            "partition_total": total_inserted,
            "partition_processed": total_processed,
            "partition_batches": batch_id + 1,
            "status": "success"
        }
    except Exception as e:
        print(f"[ERROR] Partition failed: {e}")
        import traceback
        traceback.print_exc()
        yield {
            "partition_total": total_inserted,
            "partition_processed": total_processed,
            "partition_batches": batch_id,
            "status": "error",
            "error": str(e)
        }
    finally:
        try:
            connections.disconnect(alias="default")
            print("[INFO] Milvus connection closed")
        except:
