## 方案4: 更新后的完整 convert_value 函数

```python
def convert_value(field_name, value, field_type):
    """统一的值转换函数"""
    import pickle

    try:
        if field_type == DataType.JSON:
            if value is None:
                return {}
            elif isinstance(value, Row):
                return row_to_dict(value)
            elif isinstance(value, str):
                try:
                    return row_to_dict(json.loads(value))
                except:
                    return {"raw": value}
            elif isinstance(value, dict):
                return row_to_dict(value)
            else:
                try:
                    json.dumps(value)
                    return value
                except:
                    return {"value": str(value)}

        elif field_type == DataType.VARCHAR:
            return str(value) if value is not None else ""

        elif field_type in (DataType.INT16, DataType.INT32, DataType.INT64):
            return int(value) if value is not None else 0

        elif field_type in (DataType.FLOAT, DataType.DOUBLE):
            return float(value) if value is not None else 0.0

        elif field_type == DataType.ARRAY:
            if value is None:
                return [0, 0]

            # 关键：处理 bytearray (pickle)
            if isinstance(value, (bytes, bytearray)):
                try:
                    deserialized = pickle.loads(bytes(value))
                    if isinstance(deserialized, (list, tuple)):
                        return [int(x) for x in deserialized[:2]]  # 取前两个元素
                    return [0, 0]
                except Exception as e:
                    print(f"[WARN] Pickle deserialize failed for {field_name}: {e}")
                    return [0, 0]

            # 处理字符串
            elif isinstance(value, str):
                try:
                    parsed = json.loads(value)
                    return list(parsed) if isinstance(parsed, (list, tuple)) else [0, 0]
                except:
                    return [0, 0]

            # 处理列表/元组
            elif isinstance(value, (list, tuple)):
                return list(value)

            return [0, 0]

        elif field_type == DataType.FLOAT_VECTOR:
            if value is None:
                return []
            elif isinstance(value, np.ndarray):
                return value.tolist()
            elif isinstance(value, (list, tuple)):
                return list(value)
            return []

        elif field_type == DataType.TIMESTAMPTZ:
            if value is None:
                return int(datetime.now().timestamp() * 1000)
            return int(value)

        else:
            return value

    except Exception as e:
        print(f"[WARN] Error converting {field_name}: {e}, value type: {type(value)}")

        # 返回默认值
        default_values = {
            DataType.JSON: {},
            DataType.VARCHAR: "",
            DataType.INT16: 0,
            DataType.INT32: 0,
            DataType.INT64: 0,
            DataType.FLOAT: 0.0,
            DataType.DOUBLE: 0.0,
            DataType.ARRAY: [0, 0],
            DataType.FLOAT_VECTOR: [],
        }
        return default_values.get(field_type, None)
```

